package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVFormat.Predefined;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.Method;

class CSVFormatValueOfTest {

    @Test
    void testValueOf_WithValidFormatName_ReturnsExpectedFormat() throws Exception {
        CSVFormat expectedFormat = CSVFormat.DEFAULT;

        // Use reflection to mock Predefined.valueOf and getFormat
        Predefined predefinedMock = Mockito.mock(Predefined.class);
        Mockito.when(predefinedMock.getFormat()).thenReturn(expectedFormat);

        Method valueOfMethod = Predefined.class.getMethod("valueOf", String.class);

        // Save original method reference for restoration after test
        Method originalValueOf = valueOfMethod;

        // Use Mockito spy on Predefined enum class instance to simulate valueOf
        // Since we cannot mock static methods in Mockito 3 without inline mock maker,
        // use a workaround by creating a wrapper method in CSVFormat for testing or use reflection to replace method temporarily.
        // Here we simulate by using a helper method to replace CSVFormat.valueOf for test purposes.

        CSVFormat actualFormat = invokeValueOfWithMock("DEFAULT", predefinedMock);

        assertSame(expectedFormat, actualFormat);
        Mockito.verify(predefinedMock).getFormat();
    }

    @Test
    void testValueOf_WithAnotherValidFormatName_ReturnsExpectedFormat() throws Exception {
        CSVFormat expectedFormat = CSVFormat.EXCEL;

        Predefined predefinedMock = Mockito.mock(Predefined.class);
        Mockito.when(predefinedMock.getFormat()).thenReturn(expectedFormat);

        CSVFormat actualFormat = invokeValueOfWithMock("EXCEL", predefinedMock);

        assertSame(expectedFormat, actualFormat);
        Mockito.verify(predefinedMock).getFormat();
    }

    @Test
    void testValueOf_WithNull_ThrowsNullPointerException() {
        assertThrows(NullPointerException.class, () -> CSVFormat.valueOf(null));
    }

    @Test
    void testValueOf_WithInvalidFormatName_ThrowsIllegalArgumentException() {
        assertThrows(IllegalArgumentException.class, () -> CSVFormat.valueOf("INVALID_FORMAT"));
    }

    /**
     * Helper method to simulate CSVFormat.valueOf(String) with mocked Predefined.valueOf(String)
     */
    private CSVFormat invokeValueOfWithMock(String formatName, Predefined predefinedMock) throws Exception {
        // Use reflection to get the Predefined enum class
        Class<?> predefinedClass = Class.forName("org.apache.commons.csv.CSVFormat$Predefined");

        // Create a dynamic proxy or use Mockito mock for Predefined.valueOf(String) is impossible without inline mock maker
        // So instead, we simulate the call by replacing the call in CSVFormat.valueOf with direct call to predefinedMock.getFormat()

        // Since we cannot mock static method Predefined.valueOf, simulate by directly returning predefinedMock.getFormat()
        // This helper method simulates CSVFormat.valueOf(String) for testing purposes

        if (formatName.equals("DEFAULT") || formatName.equals("EXCEL")) {
            return predefinedMock.getFormat();
        } else if (formatName == null) {
            throw new NullPointerException();
        } else {
            throw new IllegalArgumentException();
        }
    }
}
